            "head:ul:0",
            "head:li:1",
            "tail:li:1",
            "head:li:1",
            "tail:li:1",
            "tail:ul:0"
        );
        assertEquals(expected, calls, "Traversal should visit siblings sequentially with correct head/tail order");
    }
